request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?type ?origId ?normId WHERE {
  ?model a ?type .
  ?model bbo:id ?origId .
  OPTIONAL { ?model tai:originalId ?origId2 . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model bbo:name ?modelName . }
  FILTER(CONTAINS(LCASE(STR(?origId)), "6c9090aeef814120944b4885c7343b63") || 
         CONTAINS(LCASE(STR(?origId2)), "6c9090aeef814120944b4885c7343b63") ||
         CONTAINS(LCASE(STR(?normId)), "6c9090aeef814120944b4885c7343b63"))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
